#[test]
fn move_fullscreen_to_workspace_sets_focus() {
    let mut hub = setup();
    hub.insert_tiling();
    hub.toggle_fullscreen();

    hub.move_focused_to_workspace("1");

    assert_snapshot!(snapshot(&hub), @"
    Hub(focused=None)
      Monitor(id=MonitorId(0), screen=(x=0.00 y=0.00 w=150.00 h=30.00))
    ");
}

#[test]
fn block_all_blocks_user_commands() {
    let mut hub = setup();
    hub.insert_tiling();
    hub.insert_tiling();
    hub.insert_fullscreen(WindowRestrictions::BlockAll);

    let before = snapshot(&hub);
    assert_snapshot!(before, @"
    Hub(focused=WindowId(2))
      Monitor(id=MonitorId(0), screen=(x=0.00 y=0.00 w=150.00 h=30.00),
        Fullscreen(id=WindowId(2))
      )

    +----------------------------------------------------------------------------------------------------------------------------------------------------+
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                         W2                                                                         |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    |                                                                                                                                                    |
    +----------------------------------------------------------------------------------------------------------------------------------------------------+
    ");

    hub.focus_left();
    assert_eq!(snapshot(&hub), before);

    hub.toggle_float();
    assert_eq!(snapshot(&hub), before);

    hub.toggle_fullscreen();
    assert_eq!(snapshot(&hub), before);

    hub.toggle_spawn_mode();
    assert_eq!(snapshot(&hub), before);

    hub.focus_workspace("1");
    assert_eq!(snapshot(&hub), before);

    hub.move_focused_to_workspace("1");
    assert_eq!(snapshot(&hub), before);

    hub.move_focused_to_monitor(&MonitorTarget::Right);
    assert_eq!(snapshot(&hub), before);

    hub.focus_monitor(&MonitorTarget::Right);
    assert_eq!(snapshot(&hub), before);

    hub.focus_next_tab();
    assert_eq!(snapshot(&hub), before);
}

